<template>

    <section>

        <loader :is-visible="isLoading"></loader>

        <div class="col-lg-12 float-left p-0">

            <div class="form-group m-2 p-0 ">

                <label> Associate Licenses:</label>

                <div class="col-12 float-left p-0 mb-4">

                    <div v-if="addedLicensesView != ''" class="col-12 border p-1 licdetail">
                        {{ addedLicensesView }}
                    </div>

                    <div v-else class="col-12 border p-1 licdetail">
                        <strong class="text-danger">{{ $t('LicenseNotAvailable') }}</strong>
                    </div>

                </div>

            </div>

        </div>

        <br />

        <div id="divLicencedata" style="width:100%">
            <div class="col-sm-12 col-md-12 col-lg-12 form-panel mt-0 p-0">
                <div class="form-content">
                    <div class="row">
                        <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left" id="divtickettupelist">
                            <div class="heading-border">
                                <h5 class="h5"><span>{{ $t('allLicenses') }}</span></h5>
                                <button class="btn btn-sm btn-success float-right"
                                    v-if="LicenseData && LicenseData.allLicenses && LicenseData.allLicenses.length > 0 && StatusName != 'Inactive' && !isAllLicensesAssociated""
                                    @click="AddAllLicenses" :disabled="isLoading">
                                    <em class="fa fa-plus mr-1"></em>{{ $t('AddAll') }}
                                </button>
                            </div>


                            <div class="managefolder py-3">
                                <ul class="list-group" style="max-height: 400px; min-height: 200px; overflow-y: auto;">
                                    <li class="list-group-item single-action" v-if="LicenseData != null"
                                        v-for="item in LicenseData.allLicenses" :key="item.LICENSE_COUNT">
                                        {{ item.MODULE_NAME }} ({{ item.LICENSE_COUNT }})
                                        <span v-if="item.EXISTSFORUSER <= 0">
                                            <a v-if="item.LICENSE_COUNT > 0" class="aAddLicense float-right"
                                                href="javascript:;" :moduleid="item.Module_Master_Id"
                                                v-on:click="AssociateDeAssociateLicense(item, 'Associate')">
                                                <em class="fa fa-plus-circle text-success action-icon"
                                                    alt="Click to Associate License"
                                                    title="Click to Associate License"></em>
                                            </a>
                                            <a v-else class="aAddLicense float-right disabled" href="javascript:;">
                                                <em class="fa fa-plus-circle text-success action-icon disabled"
                                                    alt="License not Available" title="License not Available"></em>
                                            </a>
                                        </span>
                                        <span v-else>
                                            <a class="aAddLicense float-right disabled" href="javascript:;">
                                                <em class="fa fa-plus-circle text-success action-icon disabled"
                                                    alt="Already Associated" title="Already Associated"></em>
                                            </a>
                                        </span>
                                    </li>
                                    <li v-else class="list-group-item list_username list_img">
                                        <strong class="text-danger">{{ $t('LicenseNotAvailable') }}</strong>
                                    </li>
                                </ul>
                            </div>


                        </div>

                        <!-- <div class="mover-controls"><button type="button" data-toggle-tooltip="tooltip"
                                title="Move All Right"><em aria-hidden="true"
                                    class="fa fa-angle-double-down fa-2x d-md-none d-none "></em><em aria-hidden="true"
                                    class="fa fa-angle-double-right fa-2x d-none d-md-block d-block"></em></button><button
                                type="button" data-toggle-tooltip="tooltip" title="Move Right"><em aria-hidden="true"
                                    class="fa fa-angle-down fa-2x d-md-none d-none"></em><em aria-hidden="true"
                                    class="fa fa-angle-right fa-2x d-none d-md-block d-block"></em></button><button
                                type="button" data-toggle-tooltip="tooltip" title="Move Left"><em aria-hidden="true"
                                    class="fa fa-angle-up fa-2x d-md-none d-none"></em><em aria-hidden="true"
                                    class="fa fa-angle-left fa-2x d-none d-md-block d-block"></em></button><button
                                type="button" data-toggle-tooltip="tooltip" title="Move All Left"><em aria-hidden="true"
                                    class="fa fa-angle-double-up fa-2x d-md-none d-none"></em><em aria-hidden="true"
                                    class="fa fa fa-angle-double-left fa-2x d-none d-md-block d-block"></em></button>
                        </div> -->

                        <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left" id="divAssignedLicence"
                            v-if="StatusName != 'Inactive'">
                            <div class="heading-border">
                                <h5 class="h5"><span>{{ $t('addedLicenses') }}</span></h5>
                                <button class="btn btn-sm btn-danger float-right"
                                    v-if="LicenseData && LicenseData.addedLicenses && LicenseData.addedLicenses.length > 0 && !IS_DEFAULT"
                                    @click="RemoveAllLicenses" :disabled="isLoading">
                                    <em class="fa fa-trash mr-1"></em>{{ $t('RemoveAll') }}
                                </button>
                            </div>

                            <div class="managefolder py-3 ">
                                <ul class="list-group" style="max-height: 400px; min-height: 200px; overflow-y: auto;">
                                    <template v-if="LicenseData.addedLicenses && LicenseData.addedLicenses.length">
                                        <li v-for="item in LicenseData.addedLicenses" :key="item.MODULE_ID"
                                            class="list-group-item list_username list_img single-action"
                                            data-typename="EMER NEW GRID DGIN">
                                            {{ item.MODULE_NAME }}
                                            <a :class="IS_DEFAULT ? 'aRemoveLicense float-right disabled' : 'aRemoveLicense float-right'"
                                                href="javascript:void(0)" :moduleid="item.MODULE_ID"
                                                @click="AssociateDeAssociateLicense(item, 'De-associate')">
                                                <em :class="IS_DEFAULT ? 'fa fa-times-circle text-danger action-icon disabled' : 'fa fa-times-circle text-danger action-icon'"
                                                    alt="Click to Deassociate License"
                                                    title="Click to Deassociate License"></em>
                                            </a>
                                        </li>
                                    </template>
                                    <template v-else>
                                        <li class="list-group-item list_username list_img">
                                            <strong class="text-danger">{{ $t('LicenseNotAvailable') }}</strong>
                                        </li>
                                    </template>
                                </ul>
                            </div>


                        </div>
                    </div>
                    <div class="col-lg-6" v-if="IS_DEFAULT">
                        <div class="py-2">
                            <small>
                                <span class="mandatory">{{ $t("DefaultLicense") }}</span>
                            </small>
                        </div>
                    </div>
                    <div class="float-right mt-3">
                        <!-- <a href="javascript:;" class="btn btn-success" id="associateLicense"><i
                            class="fa fa-save mr-2"></i><span id="btnText">Save</span></a> -->

                        <!-- <a href="javascript:;" class="btn btn-info" :title="$t('BacktoList')" v-on:click="BackToList()"
                            id="associateLicenseCancel" data-toggle-tooltip="tooltip" data-original-title="Cancel"><em
                                class="fa fa-angle-double-left  mr-2"></em> {{ $t("BacktoList")
                            }}
                        </a> -->
                    </div>
                </div>
            </div>
        </div>

    </section>



</template>
<script>

import DataService from '../../services/DataService';

export default {

    components: {

    },

    props: {
        IS_DEFAULT: {
            type: Boolean
        },
        UserId: {
            type: Number
        },
        userType: {
            type: Number
        },
        UserTypeName: {
            type: String
        },
        StatusName: {
            type: String
        }
    },
    data() {
        return {
            isLoading: false,
            LicenseData: null,
            addedLicensesView: ''
        }
    },
    computed: {
        isAllLicensesAssociated() {
            if (!this.LicenseData || !this.LicenseData.allLicenses) return false;

            // check if every item EXISTSFORUSER = 1
            return this.LicenseData.allLicenses.every(
                item => item.EXISTSFORUSER == 1
            );
        }
    },

    created() {

        var vm = this;
        vm.GetAssociateLicense();

    },
    methods: {

        BackToList() {

            var vm = this;
            vm.$router.push({
                name: "UserIndex",
                path: "/User/Index"
            });

        },

        async GetAssociateLicense() {
            debugger
            try {

                var vm = this;
                vm.isLoading = true;
                let url = `userType=${vm.userType}&createdUserId=${vm.UserId}`;
                const response = await DataService.GetAssociateLicenses(url);

                if (response.data != null || response.data != '') {
                    vm.isLoading = false;
                    vm.LicenseData = response.data;
                    let addedLicensesViewString = '';
                    vm.LicenseData.addedLicenses.forEach(element => {
                        if (element.MODULE_NAME) {
                            addedLicensesViewString += (addedLicensesViewString.length > 0 ? ', ' : '') + element.MODULE_NAME;
                        }
                    });
                    vm.addedLicensesView = addedLicensesViewString;

                }

            } catch (error) {
                vm.isLoading = false;
                console.error('Error in GetAssociateLicense:', error);
            }
        },
        async AssociateDeAssociateLicense(item, AssociateValue) {
            debugger
            try {
                var vm = this;
                vm.isLoading = true;
                var params = `moduleMasterID=${item.Module_Master_Id != undefined ? item.Module_Master_Id : item.MODULE_ID}&userId=${vm.UserId}&userType=${vm.UserTypeName}&actionType=${AssociateValue}`;
                const response = await DataService.GetAssociateDeAssociateLicense(params);
                if (response.data != null) {
                    vm.isLoading = false;
                    vm.addedLicensesView = "";
                    vm.LicenseData = response.data;
                    let addedLicensesViewString = '';
                    if (vm.LicenseData.addedLicenses.length > 0) {
                        vm.LicenseData.addedLicenses.forEach(element => {
                            if (element.MODULE_NAME) {
                                addedLicensesViewString += (addedLicensesViewString.length > 0 ? ', ' : '') + element.MODULE_NAME;
                            }
                        });

                        vm.addedLicensesView = addedLicensesViewString;

                        if (AssociateValue == "Associate") {
                            vm.isLoading = false;
                            vm.ShowAlert(vm.$t("AssociateLicenseSuccess"), "success", vm.$t('Alert'));



                        } else if (AssociateValue == "De-associate") {
                            vm.isLoading = false;
                            vm.ShowAlert(vm.$t("DeAssociateLicenseSuccess"), "success", vm.$t('Alert'));


                        }
                    }
                    else {
                        vm.isLoading = false;
                        vm.ShowAlert('Please Purchase more license by upgrade subscription!', "failure", true, vm.$t("Alert"));
                    }

                }

            } catch (error) {
                console.error('Error in AssociateDeAssociateLicense:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        async RemoveAllLicenses() {
            debugger
            try {
                var vm = this;
                vm.isLoading = true;

                if (vm.LicenseData && vm.LicenseData.addedLicenses && vm.LicenseData.addedLicenses.length > 0) {
                    //for (let item of vm.LicenseData.addedLicenses) {
                    var params = `moduleMasterID=0&userId=${vm.UserId}&userType=${vm.UserTypeName}&actionType=De-associate&IsRemovedAll=true&refCode=AssociatePage`;
                    const response = await DataService.GetAssociateDeAssociateLicense(params);
                    if (response.data != null) {
                        vm.LicenseData = response.data;
                    }
                    //}

                    vm.isLoading = false;
                    vm.addedLicensesView = "";
                    vm.ShowAlert(vm.$t("DeAssociateLicenseSuccess"), "success", vm.$t('Alert'));
                }
            } catch (error) {
                console.error('Error in RemoveAllLicenses:', error);
                vm.isLoading = false;
            }
        },
        async AddAllLicenses() {
            debugger
            try {
                var vm = this;
                vm.isLoading = true;

                if (vm.LicenseData && vm.LicenseData.allLicenses && vm.LicenseData.allLicenses.length > 0) {
                    for (let item of vm.LicenseData.allLicenses) {
                        var params = `moduleMasterID=${item.Module_Master_Id}&userId=${vm.UserId}&userType=${vm.UserTypeName}&actionType=Associate&IsRemovedAll=false`;
                        const response = await DataService.GetAssociateDeAssociateLicense(params);
                        if (response.data != null) {
                            vm.LicenseData = response.data;
                        }
                    }

                    vm.addedLicensesView = "";
                    let addedLicensesViewString = '';
                    if (vm.LicenseData.addedLicenses && vm.LicenseData.addedLicenses.length > 0) {
                        vm.LicenseData.addedLicenses.forEach(element => {
                            if (element.MODULE_NAME) {
                                addedLicensesViewString += (addedLicensesViewString.length > 0 ? ', ' : '') + element.MODULE_NAME;
                            }
                        });
                        vm.addedLicensesView = addedLicensesViewString;
                    }
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t("AssociateLicenseSuccess"), "success", vm.$t('Alert'));
                }
            } catch (error) {
                console.error('Error in AddAllLicenses:', error);
                vm.isLoading = false;
            }
        },


    },

}
</script>
<style></style>